import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"How to Hack and Upgrade Your Car, Using CAN Bus","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/car-hacking/how-to-hack-and-upgrade-your-car-using-can-bus.md","filePath":"obd2/car-hacking/how-to-hack-and-upgrade-your-car-using-can-bus.md"}'),i={name:"obd2/car-hacking/how-to-hack-and-upgrade-your-car-using-can-bus.md"};function n(s,e,l,h,c,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="how-to-hack-and-upgrade-your-car-using-can-bus" tabindex="-1">How to Hack and Upgrade Your Car, Using CAN Bus <a class="header-anchor" href="#how-to-hack-and-upgrade-your-car-using-can-bus" aria-label="Permalink to &quot;How to Hack and Upgrade Your Car, Using CAN Bus&quot;">​</a></h1><h2 id="introduction-how-to-hack-and-upgrade-your-car-using-can-bus" tabindex="-1">Introduction: How to Hack and Upgrade Your Car, Using CAN Bus <a class="header-anchor" href="#introduction-how-to-hack-and-upgrade-your-car-using-can-bus" aria-label="Permalink to &quot;Introduction: How to Hack and Upgrade Your Car, Using CAN Bus&quot;">​</a></h2><p>This document is aimed at those unfamiliar with CAN bus or the reverse engineering process, it will cover some very basic and advanced concepts.</p><p>It is assumed that the reader has moderate programming knowledge and basic electronics knowledge, however, links to resources will be provided in each section for those that need additional information.</p><h3 id="in-this-tutorial-we-will-cover" tabindex="-1">In this tutorial we will cover: <a class="header-anchor" href="#in-this-tutorial-we-will-cover" aria-label="Permalink to &quot;In this tutorial we will cover:&quot;">​</a></h3><ul><li>What is CAN bus?</li><li>The basics of an Arduino microcontroller.</li><li>Basic electronics knowledge.</li><li>CAN bus electronics.</li><li>How to retrieve data from a vehicle’s CAN bus network.</li><li>How to interpret data from a CAN bus network.</li><li>How to build a software or hardware interface to interpret the data.</li></ul><h4 id="required-electronics" tabindex="-1">Required Electronics <a class="header-anchor" href="#required-electronics" aria-label="Permalink to &quot;Required Electronics&quot;">​</a></h4><p>To follow this tutorial&#39;s content properly, you will need several key items which are listed below. Links to online sellers are included in the equipment sources section.</p><h4 id="you-will-need" tabindex="-1">You will need: <a class="header-anchor" href="#you-will-need" aria-label="Permalink to &quot;You will need:&quot;">​</a></h4><ul><li>A SparkFun CAN bus shield</li><li>A micro SD card.</li><li>A DB9 to OBD connector, for connecting to the diagnostics port of the vehicle.</li><li>Arduino UNO</li><li>Arduino Pin headers for soldering to the CAN shield</li><li>Arduino Male to Male, Male to Female and Female to Female jumper wires.</li><li>Soldering Iron and solder.</li></ul><p>Please note that you do not need the exact hardware listed, you can still use this tutorial should you use alternative hardware such as a Seeeduino CAN bus shield, however, the code provided will only work with the Sparkfun shield, but can be modified for other hardware.</p><h3 id="step-1-​required-knowledge" tabindex="-1">Step 1: ​Required Knowledge <a class="header-anchor" href="#step-1-​required-knowledge" aria-label="Permalink to &quot;Step 1: ​Required Knowledge&quot;">​</a></h3><h4 id="required-knowledge" tabindex="-1">Required Knowledge <a class="header-anchor" href="#required-knowledge" aria-label="Permalink to &quot;Required Knowledge&quot;">​</a></h4><p>In order to follow this tutorial, you need: Some programming experience with C++, Java or similar programming languages, if you are not, there will be some help provided by the tutorial, but please refer to the electronics and programming resources section. Some electronics knowledge, you need to understand basic electronics concepts such as what voltage, current and a circuit are. If you do not know, there will be some help provided by the tutorial, but please refer to electronics and programming resources section.</p><h4 id="required-software-arduino-ide" tabindex="-1">Required software: Arduino IDE <a class="header-anchor" href="#required-software-arduino-ide" aria-label="Permalink to &quot;Required software: Arduino IDE&quot;">​</a></h4><p>To work with Arduino and the Sparkfun CAN bus shield you will need to download some software, the most important piece of software is the Arduino programming interface, referred to as the Arduino IDE which can be downloaded from the link in the software sources section.</p><h4 id="required-software-serial-plot" tabindex="-1">Required software: Serial Plot <a class="header-anchor" href="#required-software-serial-plot" aria-label="Permalink to &quot;Required software: Serial Plot&quot;">​</a></h4><p>To efficiently process and interpret the data received from the CAN bus network, it is recommended you install SerialPlot. It is a software tool that allows you to map the values outputted from the CAN bus network to several live graphs; this will make spotting data patterns and changes in behaviour much easier than with a raw data feed.</p><h3 id="step-2-safety-and-legality" tabindex="-1">Step 2: Safety and Legality <a class="header-anchor" href="#step-2-safety-and-legality" aria-label="Permalink to &quot;Step 2: Safety and Legality&quot;">​</a></h3><h4 id="safety-and-legality" tabindex="-1">Safety and Legality <a class="header-anchor" href="#safety-and-legality" aria-label="Permalink to &quot;Safety and Legality&quot;">​</a></h4><p>Please note, the systems you are working on are electrical, as such, there are precautions you should always take.</p><p><strong>When working with electrical systems that may have high voltage such as elevators.</strong></p><ul><li>Wear nonconductive or electrically insulating gloves</li><li>Remove all jewellery</li><li>Wear long sleeve overalls</li><li>Wear any other appropriate Personal Protective Equipment (PPE)</li></ul><p><strong>When working with electrically sensitive systems that may be damaged by static discharge take appropriate steps to protect yourself and others.</strong></p><ul><li>Wear a grounding wrist strap that is connected to the chassis of the device you are working on.</li><li>Wear nonconductive or electrically insulating gloves.</li><li>Avoid wearing clothing that builds a static charge</li></ul><p><strong>When working with systems that may cause injury to yourself or others, practice safe behaviours.</strong></p><ul><li>Do not test systems in areas that put anyone in danger</li><li>Do not test systems that put yourself in danger without appropriate precautions.</li><li>Do not do anything to a system without research or investigation into the possible ramifications.</li><li>Do not leave a system unattended or accessible whilst in a state where it may cause injury.</li></ul><h4 id="legal-requirements" tabindex="-1">Legal requirements <a class="header-anchor" href="#legal-requirements" aria-label="Permalink to &quot;Legal requirements&quot;">​</a></h4><p>Different countries have different regulations, systems that carry the potential of putting yourself or others in harm&#39;s way often have legal requirements or restrictions as to what can be done to them or requirements they must meet. Should you decide to work on an existing system, please make sure to research the legality of what you are doing and the requirements for that work.</p><p>In this project a vehicles dashboard cluster is produced, there are a number of legal requirements and restrictions for that device such as the cluster must have the ability to display specific types of information at all times, the cluster must display information within specific tolerances, and the cluster must display specific indicators at specific times.</p><h4 id="disclaimer" tabindex="-1">Disclaimer <a class="header-anchor" href="#disclaimer" aria-label="Permalink to &quot;Disclaimer&quot;">​</a></h4><p>Every effort is made to ensure that the information provided is accurate, but no legal responsibility is accepted for any errors, omissions, misleading statements, damages or injuries that may occur whilst utilizing this document.</p><h3 id="step-3-​what-is-can-bus" tabindex="-1">Step 3: ​What Is CAN Bus? <a class="header-anchor" href="#step-3-​what-is-can-bus" aria-label="Permalink to &quot;Step 3: ​What Is CAN Bus?&quot;">​</a></h3><h4 id="what-is-can-bus" tabindex="-1">What is CAN bus? <a class="header-anchor" href="#what-is-can-bus" aria-label="Permalink to &quot;What is CAN bus?&quot;">​</a></h4><p>CAN-bus (Controller Area Network-bus) is the broad name for a set of standards which define the way for separate but connected devices to communicate with each other. Its primary uses are in the industrial, automotive and aviation sectors due to its extensive error checking, flexible implementation and built-in redundancy.</p><p>Most large equipment you see day to day uses CAN-bus in one way or another, elevators and airliners almost always use CAN-bus due to a number of factors including how long the communication wires can be without data corruption. Cars, elevators, aircraft, robotics and other systems all use CAN-bus because of its ability to operate with one pair of wires but hundreds of separate modules reliably (Avionics, 2018).</p><p>As with many other communication protocols, CAN does not define precisely how the data should be encoded into the CAN bus data frames, only its layout or format.</p><p>As such, the data being converted to binary could be done in any way the user likes, 001 or 010 or 100 or 111 could all mean the letter ‘A’, but each is a different way of representing that data, they are all proprietary implementations. The issue with proprietary implementations is the inability to perform maintenance without documentation which companies tend not to release.</p><h4 id="vehicle-network-topology" tabindex="-1">Vehicle Network Topology <a class="header-anchor" href="#vehicle-network-topology" aria-label="Permalink to &quot;Vehicle Network Topology&quot;">​</a></h4><p>The topology of a network refers to how multiple devices are connected. A bus topology is a type of network where all devices are connected to one communication line. Please refer to the electronics and programming resources page if you are unfamiliar with network topologies.</p><p>Early on in the adoption of CAN bus and the OBD diagnostics system, manufacturers implemented the CAN system because of its benefits, but used simple topologies, such as a bus topology where every device on the network was connected to a single bus, this meant all ECU’s were directly accessible on the diagnostics port and could communicate with each other. As CAN bus became more popular, other methods of implementation occurred. The method most common in vehicles today, including the vehicle being used for this project is a series of electrically separate networks that run between a small number of VCU’s acting as repeaters only for necessary information. The best description of this topology is a hybrid layout of a star, tree and bus topology (Walz, 2018).</p><p>On the vehicle being used for this project, the main VCU called the BSI (Built-in Systems Interface) branches out to other VCUs in the vehicle from the centre of its star network. The other modules on the network may branch to separate modules or may have several modules all connected on a single bus from it</p><h3 id="step-4-tapping-into-a-can-bus-network" tabindex="-1">Step 4: Tapping Into a CAN Bus Network <a class="header-anchor" href="#step-4-tapping-into-a-can-bus-network" aria-label="Permalink to &quot;Step 4: Tapping Into a CAN Bus Network&quot;">​</a></h3><h4 id="how-to-access-your-system" tabindex="-1">How to access your system <a class="header-anchor" href="#how-to-access-your-system" aria-label="Permalink to &quot;How to access your system&quot;">​</a></h4><p>In order to follow along with the project, you will need to have a device with CAN bus or other protocols supported by the Sparkfun shield. You also need to find documentation on your system such as wiring diagrams; if you cannot locate these resources, then you may have to make your own wiring diagram however this will require specific electronics knowledge.</p><p>When working with CAN bus, you will need the ignition in the vehicle to be on so that the systems are communicating; the engine does not need to be running, there just needs to be power to devices such as the stereo and dashboard cluster.</p><h4 id="locate-a-wiring-diagram" tabindex="-1">Locate a wiring diagram <a class="header-anchor" href="#locate-a-wiring-diagram" aria-label="Permalink to &quot;Locate a wiring diagram&quot;">​</a></h4><p>The image for this step shows a partial wiring diagram for a Peugeot 407.</p><p>With most vehicles, you can purchase a Haynes manual or locate a wiring diagram as they are very necessary when doing any kind of electronics work with a vehicle. The diagrams will not only tell you where CAN bus lines are in the vehicle but may also tell you important things about the connection such as how the devices are connected, which pins of the plug those lines go to etc.</p><p>If you are working on a non-automotive system such as an elevator or aircraft, you will likely find the wiring diagram glued to the back of the panel covering the wires or in a pouch of some kind for maintenance.</p><p>Unfortunately, locating these diagrams is a process specific to your vehicle or system, however, recommended avenues to locate these diagrams include:</p><ul><li>Haynes Manual</li><li>Maintenance manual for the equipment</li><li>Diagrams glued to internal panels</li><li>Search engine searches</li><li>Ask a local garage</li><li>Ask an authorized dealer or garage</li></ul><p>If you are unable to locate a wiring diagram from any of these sources, then there are alternative options.</p><h4 id="documenting-the-process" tabindex="-1">Documenting the process <a class="header-anchor" href="#documenting-the-process" aria-label="Permalink to &quot;Documenting the process&quot;">​</a></h4><p>Because of the complexity of this project, it is highly recommended that you document everything you have done for future reference, you will need to take notes on wire colours, voltages, data patterns and you may need to make wiring diagrams.</p><p>These documents will allow you to work on your project whilst away from the system you are tapping into; it will also make debugging problems with your methods or implementation easier for you and for others that encounter your work.</p><h3 id="step-5-part-1-accessing-the-can-bus-lines" tabindex="-1">Step 5: Part 1: Accessing the CAN Bus Lines <a class="header-anchor" href="#step-5-part-1-accessing-the-can-bus-lines" aria-label="Permalink to &quot;Step 5: Part 1: Accessing the CAN Bus Lines&quot;">​</a></h3><h4 id="_1-1-diagnostics-port" tabindex="-1">1.1 Diagnostics port <a class="header-anchor" href="#_1-1-diagnostics-port" aria-label="Permalink to &quot;1.1 Diagnostics port&quot;">​</a></h4><p>In the Automotive industry, the typical way to access CAN bus in a vehicle is the ODB2 port which is a standardized connector that, as mandated by law, has been a requirement in all consumer vehicles since 2006 and in most since 1999, in Europe and the US. Vehicles are required to use a standardized communication system such as CAN bus or Van bus (OBD Solutions, 2017).</p><p>OBD2 ports typically look like the one pictured in this step. They all have that distinctive shape. By European and US law, the port has to be accessible from the driver&#39;s seat without specialized tools. However, it may be hidden behind a removable panel, in a closed compartment or in a hard to reach location such as under the steering column.</p><h4 id="_1-2-tapping-into-can-bus-wires" tabindex="-1">1.2 Tapping into CAN bus wires. <a class="header-anchor" href="#_1-2-tapping-into-can-bus-wires" aria-label="Permalink to &quot;1.2 Tapping into CAN bus wires.&quot;">​</a></h4><p>Depending on what your intentions are you may not be able to use the diagnostics port to access the CAN network in your vehicle. In this project, a custom dashboard cluster is going to be built to use the data created during the reverse engineering process, but the diagnostics port does not output all the information needed for a dashboard cluster nor is it in the location of the cluster. To tap into the wires, you may have to pierce the plastic covers, remember to tape the holes over after you have finished with the wires.</p><h4 id="_1-3-make-your-own-wiring-diagram-or-notes" tabindex="-1">1.3 Make your own wiring diagram or notes. <a class="header-anchor" href="#_1-3-make-your-own-wiring-diagram-or-notes" aria-label="Permalink to &quot;1.3 Make your own wiring diagram or notes.&quot;">​</a></h4><p>The electronics and programming section contains a link to an in-depth tutorial on locating CAN bus lines. However some basic principles will be discussed here, in order to make your own diagram, you could ask someone skilled or proficient in electronics design to assist you, or you can try it yourself.</p><p>You will need a Multimeter and an oscilloscope; you can purchase very cheap versions of these products from the links in the equipment sources page.</p><p>The recommended oscilloscope is the DSO138 available from many sources online for about £20/$25; any multimeter will be sufficient.</p><p>CAN bus operates at 0 to 5v. When data is not being sent the two wires should be at about 2v relative to the vehicles ground or 0v relative to each other. When data is sent down the CAN wires, a pulse is represented by a change of 2v. In order to locate the CAN lines, you will need to connect the oscilloscope to the CAN high and CAN low wires. To locate those wires, you can find clues as to which wires they may be by looking at the wire colouring.</p><p>Vehicles tend to use consistent wire colours, as such if you look at the rear of the OBD2 port for the CAN bus lines going to it, you will see some of the wire colours the vehicle uses to represent different wires, make a note of what each colour wire goes to. Specifically noting the CAN line colours, the wires for different CAN networks can be different colours, so this is not a guaranteed way to find them however if you see wires that are undocumented colours, they could be the CAN lines.</p><h4 id="_1-4-practice" tabindex="-1">1.4 Practice <a class="header-anchor" href="#_1-4-practice" aria-label="Permalink to &quot;1.4 Practice&quot;">​</a></h4><p>Test your equipment works and refine your testing methods by connecting the multimeter and Oscilloscope to the OBD2 port CAN bus pins, you should be able to see the signal pulses on pins 6 and 14, if you connect the multimeter with the 5v DC or closest setting, you should see a fluctuating voltage of a maximum 5v and voltage difference of about 2v when you connect between the vehicles ground pins 4 or 5 and CAN bus pins 6 or 14, if you cannot detect CAN bus data on those pins, you vehicle may be too old or uses a different protocol.</p><p>Observe the colours of the wires connected to the rear of the diagnostics port; you will likely see:</p><p>· Red wires which connect to +12v pins such as pin 16 of the OBD port.</p><p>· Black wires which connect to ground pins such as 4 and 5 of the OBD port</p><p>· The other wires can be whatever colour the manufacturer chooses as they aren’t standardized.</p><h4 id="_1-5-manually-locating-can-bus-lines" tabindex="-1">1.5 Manually locating CAN bus lines. <a class="header-anchor" href="#_1-5-manually-locating-can-bus-lines" aria-label="Permalink to &quot;1.5 Manually locating CAN bus lines.&quot;">​</a></h4><p>At the point where you are going to access the CAN bus lines, if it a stereo, there will likely be several wires going to speakers, microphones and other devices. These other wires can make determining the CAN bus lines difficult. However, there is almost always a wiring diagram for the stereo in a vehicle, so go and check online first! Otherwise look at the wire colour from the target lines, to see if they match the CAN lines colour from the OBD2 connector, if the colours match, it is likely that they are CAN lines, if they do not, check if they match the other wire colours from your notes, you should be able to rule out what wires are not CAN bus though colour comparisons and may be left with a few unknown wires, document everything observed into your diagram or notes.</p><p>Alternatively if you are tapping into a removable module such as the dashboard cluster, if possible, observe the circuit board the wires are connected to, sometimes you can figure out which pins are CAN bus by observing two electrical traces from the plug that go directly into a large chip without branching out to other areas of the board.</p><p>For all of the different ways to try locating CAN bus lines, try repeating the process from 1.4 Practice, on the wires you are targeting. If you are unable to figure out which lines are CAN bus, try probing the matching pairs of wires with the oscilloscope to see pulses of data like those seen when practising, if you are still unable to locate the CAN lines, there may not be CAN lines going to that specific device.</p><h4 id="_1-6-cannot-find-can-bus-lines" tabindex="-1">1.6 Cannot find CAN bus lines <a class="header-anchor" href="#_1-6-cannot-find-can-bus-lines" aria-label="Permalink to &quot;1.6 Cannot find CAN bus lines&quot;">​</a></h4><p>If you cannot locate the CAN bus lines, then it is likely your vehicle does not have any in the location you are trying to find them, in this case, try to find the CAN bus lines to a module more likely to have CAN bus such as the stereo or LCD panel (if your vehicle has one) and note the wire colors, you may be able to achieve your desired goal using the CAN bus lines you have found by using a wireless adaptor or extension wires to the place you need them.</p><h4 id="_1-7-successfully-found-can-bus-lines" tabindex="-1">1.7 Successfully found CAN bus lines <a class="header-anchor" href="#_1-7-successfully-found-can-bus-lines" aria-label="Permalink to &quot;1.7 Successfully found CAN bus lines&quot;">​</a></h4><p>If you have successfully found CAN bus lines, then you should do the following:</p><ul><li>Make a note of the other wires near the CAN lines or connected to the same device the CAN lines are connected to.</li><li>Read the voltages from the wires with the multimeter by connecting one probe to ground and the other to each of the wires, noting this information down.</li><li>Draw a clean diagram of the circuit you are going to interface with.</li></ul><h4 id="_1-8-next-steps" tabindex="-1">1.8 Next steps <a class="header-anchor" href="#_1-8-next-steps" aria-label="Permalink to &quot;1.8 Next steps&quot;">​</a></h4><p>Now that you have successfully accessed the CAN bus lines of your systems you need to think about what types of data you expect to retrieve from the network. For instance, if you are connected to the dashboard clusters, you will be expecting information such as:</p><ul><li>ABS ( Anti-Lock Braking System)</li><li>ESP ( Electronic Stability Control )</li><li>SRS (Supplement restrain system AKA: Airbags)</li><li>Seat belt not in use</li><li>Tire pressure warning</li><li>Indicators (independent left and right or joined light)</li><li>All external lighting configurations ( Beam, dipped, fog, side lights, hazards etc.)</li><li>Speed</li><li>Engine Faults.</li><li>Tachometer ( Distance counter )</li></ul><p>Note the expected information down in a grid like the one in the pictures for this step</p><p>At the moment you will only be populating the information and ID columns.</p><h3 id="step-6-part-2-reading-data-from-the-can-bus" tabindex="-1">Step 6: Part 2: Reading Data From the CAN Bus <a class="header-anchor" href="#step-6-part-2-reading-data-from-the-can-bus" aria-label="Permalink to &quot;Step 6: Part 2: Reading Data From the CAN Bus&quot;">​</a></h3><h4 id="reading-data-from-the-can-bus" tabindex="-1">Reading data from the CAN bus <a class="header-anchor" href="#reading-data-from-the-can-bus" aria-label="Permalink to &quot;Reading data from the CAN bus&quot;">​</a></h4><p>Now that you have found the CAN bus lines and have noted down the expected data, you are going to connect to the CAN network with the use of the Arduino and Sparkfun shield.</p><h4 id="_2-1-connecting-the-arduino-to-the-shield" tabindex="-1">2.1 Connecting the Arduino to the Shield <a class="header-anchor" href="#_2-1-connecting-the-arduino-to-the-shield" aria-label="Permalink to &quot;2.1 Connecting the Arduino to the Shield&quot;">​</a></h4><p>To use the Sparkfun CAN bus shield, you will need to connect the shield to the Arduino. When you ordered your CAN bus shield, it likely did not come with the pins pre-soldered which means you will have to solder them on yourself.</p><p>Please refer to the electronics and programming resources at the bottom on this document for help with soldering and setting up the Sparkfun shield. Once soldered connect the Sparkfun board to the Arduino as you would with any Arduino shield</p><p>Take note that there are two wires coming off the top of the CAN bus shield, these wires are connected to the CAN high and low pins of the shield and on the other end, the CAN high and low pins of a cars dashboard cluster.</p><p>This setup allows the Arduino to communicate with the cluster; commands can be sent to control the cluster and received to detect replies from the cluster.</p><h4 id="_2-2-connecting-to-the-can-bus" tabindex="-1">2.2 Connecting to the CAN bus <a class="header-anchor" href="#_2-2-connecting-to-the-can-bus" aria-label="Permalink to &quot;2.2 Connecting to the CAN bus&quot;">​</a></h4><p>CAN bus has different modes for communication; it also has different speeds which are call baud rates. To successfully connect to the CAN system you will need to determine the baud rate. You can use an oscilloscope and count the time between pulses to determine the baud rate of the CAN bus network, depending on your oscilloscope, standard baud rates are 125 kbit/s, 250 kbit/s, 500 kbit/s and 1 Mbit/s. Please refer to the electronics and programming resources if you need help with this process. Alternatively, you can experiment to find the correct baud rate.</p><h4 id="_2-3-physically-connecting-the-arduino-to-the-vehicles-can-bus" tabindex="-1">2.3 Physically connecting the Arduino to the vehicles CAN bus. <a class="header-anchor" href="#_2-3-physically-connecting-the-arduino-to-the-vehicles-can-bus" aria-label="Permalink to &quot;2.3 Physically connecting the Arduino to the vehicles CAN bus.&quot;">​</a></h4><p>As shown mentioned in the previous section, you can connect the Arduino to the CAN bus lines via the pins on the top of the Sparkfun shield. If you choose to connect to the CAN bus in this manner, take care to connect the lines the correct way around, damage will not occur if you connect incorrectly, the shield will simply not receive any data.</p><p>The alternative method for connecting the shield to the vehicle is to use the DB9 to OBD2 adaptor cable which plugs into the large serial port on the Sparkfun shield and the diagnostics port on the vehicle, it is recommended that you follow this tutorial using the diagnostic port first as you reduce the risk of harming the vehicle.</p><h3 id="step-7-part-3-retrieving-data-from-the-network" tabindex="-1">Step 7: Part 3: Retrieving Data From the Network <a class="header-anchor" href="#step-7-part-3-retrieving-data-from-the-network" aria-label="Permalink to &quot;Step 7: Part 3: Retrieving Data From the Network&quot;">​</a></h3><h4 id="retrieving-data-from-the-network" tabindex="-1">Retrieving data from the network <a class="header-anchor" href="#retrieving-data-from-the-network" aria-label="Permalink to &quot;Retrieving data from the network&quot;">​</a></h4><p>DO NOT CONNECT TO THE CAN BUS BEFORE READING SECTION 3.1 Once you have connected, you need to set the baud rate in software. Section 2.2 provides a way to determine the baud rate of the CAN bus network you are connecting to; however, if you do not have an oscilloscope or cannot figure out how to use it, there is an alternative method.</p><p>Connect the Arduino to the computer and upload the code provided in the demonstration code entitles “Demo 1” at the end of this document. If you get errors such as “No such file or directory” when trying to upload the code, this means you have not installed the library for the Sparkfun board correctly, If you get “An error occurred while uploading the sketch” this means the Arduino is not connected or the software has not been set up correctly. Other errors likely mean you have incorrectly copied the code.</p><p>With the code uploaded to the Arduino successfully, you will have it configured to connect to a CAN bus network operating at 500kbps as this is what the demo code is set to which the line “if(Canbus.init(CANSPEED_500)){ “. You can change the configured speed by modifying the value of 500 to a different value, e.g: Canbus.init(CANSPEED_125) for 125kbps.</p><h4 id="_3-1-guessing-the-baud-rate" tabindex="-1">3.1 Guessing the baud rate. <a class="header-anchor" href="#_3-1-guessing-the-baud-rate" aria-label="Permalink to &quot;3.1 Guessing the baud rate.&quot;">​</a></h4><p>Depending on the network you are connecting to, the baud rate may have different speeds, the diagnostics connector in a vehicle is generally 500kbps or 1mbps due to the amount of data it is outputting. However, other devices such as the stereo may only be 125kbps because it only outputs a small amount of data. For the vehicle used in the project ( A Peugeot 407 ), the diagnostics port runs as 500kbps whereas the cluster runs at 125kbps.</p><p>Before you start guessing your baud rate, be ready to unplug the CAN bus lines very quickly and make sure the engine is not running, if you connect to a CAN bus network at the wrong baud rate, you can cause glitching to occur which may make the vehicle&#39;s systems misbehave.</p><p>With the Arduino connected to the computer and serial monitor open, you should see the repeating message: “No data”, this means the Arduino is connected to the computer correctly, and data is coming in, at this point connect to the CAN bus network, you should instantly see data coming in, if you do not, but nothing else happens such as a check engine light, check your connection. • If glitching does not occur but you do not receive any data, and you have connected via the pins on the shield, you may have the CAN bus lines connected the wrong way around or to the wrong wires. • If no glitching occurs and you have no data, check that you did not accidentally disconnect the Arduino from the computer by seeing if the no data message is still coming in or by closing the serial monitor window and opening it again. If you have no success and are connected via the CAN H and L pins rather than the diagnostics port, please try the process on the diagnostics port to determine if the hardware setup is at fault.</p><h4 id="_3-2-requesting-diagnostic-can-data" tabindex="-1">3.2 Requesting diagnostic CAN data <a class="header-anchor" href="#_3-2-requesting-diagnostic-can-data" aria-label="Permalink to &quot;3.2 Requesting diagnostic CAN data&quot;">​</a></h4><p>If you are following these instructions whilst connected to the diagnostics port of the vehicle, you may be able to request diagnostic data from the diagnostic CAN network fi your vehicle is using the same CAN bus standard as a Peugeot 407.</p><p><strong>Read part 4 then if you are unfamiliar with CAN bus frames.</strong></p><p>When making a diagnostic request for data, the query consists of 4 variable bytes.<br> ID, the first byte is ID which is always 2015 ( A data request ).</p><ul><li>Ch1, the second is the query length (Always 2 bytes for SAE Standard)</li><li>Ch2, the third byte is the mode (Wikipedia, 2017).</li><li>Ch3, the fourth is the data requested, these are called Parameter ID’s (PIDS)[1]</li><li>Ch4 – ch8 are unused in a request.</li></ul><p>You send the following frame to get back diagnostics data:</p><p>The PID for throttle position is 17, as such we send the following:<br> &lt; Request 2015, query length 2, Mode 1 Live data, PID 17,0,0,0,0,0 &gt;<br> The reply is: &lt; requested 17, Throttle = 0 to 255, 0,0,0,0&gt; or &lt;2024, 3,65,17, 0,0,0,0,0&gt;</p><p>The unused last five channels may or may not all be used to represent the requested PID depending on its precision requirements.</p><p>Most are of a range to be adequately represented when divided into values between 0 and 255. However, some may require more granularity such as RPM.In order to send data into the network, you will need to use the code from the demonstration code entitled “Demo 2”, you will need to changes the values in the bottom of the code for the ID which looks like this: “message.id = 0;” to the Data request ID of 2015. You will also need to change the code for each channel from this: message.data[0] = 0; to the respective value as explained above.</p><ul><li>message.id = 2015; //The ID for the frame you are sending</li><li>message.data[0] = 2; // place your custom value for ch1 here</li><li>message.data[1] = 1; // place your custom value for ch2 here</li><li>message.data[2] = 17; // place your custom value for ch3 here</li><li>message.data[3] = 0; // place your custom value for ch4 here</li><li>message.data[4] = 0; // place your custom value for ch5 here</li><li>message.data[5] = 0; // place your custom value for ch6 here</li><li>message.data[6] = 0; // place your custom value for ch7 here</li><li>message.data[7] = 0; // place your custom value for ch8 here</li></ul><p>which will result in the following being sent to the CAN network: &lt; 2015, 2, 1, 17,0,0,0,0,0 &gt;</p><p>[1] <a href="https://en.wikipedia.org/wiki/OBD-II_PIDs" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/OBD-II_PIDs</a></p><h3 id="step-8-part-4-what-is-a-can-bus-data-frame" tabindex="-1">Step 8: Part 4: What Is a CAN Bus Data Frame <a class="header-anchor" href="#step-8-part-4-what-is-a-can-bus-data-frame" aria-label="Permalink to &quot;Step 8: Part 4: What Is a CAN Bus Data Frame&quot;">​</a></h3><h4 id="what-is-a-can-bus-data-frame" tabindex="-1">What is a CAN bus data frame <a class="header-anchor" href="#what-is-a-can-bus-data-frame" aria-label="Permalink to &quot;What is a CAN bus data frame&quot;">​</a></h4><p>Every manufacturer uses their own encoding method for packaging data into a CAN bus communication frames. This is a similar concept to basic encryption as the goal is not compression only transformation into the format required for the form of communication.</p><p>A CAN bus frame is complex, there are multiple types, but the most common type of frame (A base frame) consists of 11 identifier subframes, only two of which are relevant for most users, these are subframes two and seven.</p><p>Subframe two is up to 11 bits in size; it is the ID of the frame. Subframe seven is the data field; it stores data relevant to the ID in eight comma-separated, one-byte values (Vector.com, 2018).</p><p>Please note that different CAN bus networks in the same vehicle may use the same ID’s to refer to different data, do not presume that because the networks are within the same vehicle, they all use the same format.</p><h4 id="_4-1-diagnostic-port-raw-can-data" tabindex="-1">4.1 Diagnostic Port, Raw CAN Data <a class="header-anchor" href="#_4-1-diagnostic-port-raw-can-data" aria-label="Permalink to &quot;4.1 Diagnostic Port, Raw CAN Data&quot;">​</a></h4><p>the smallest image Is the layout of useful data in a CAN bus message; it is called a “frame”. The layout you see is the format that the Arduino is outputting with the demo code provided in the demonstration code entitled “Demo 1”.</p><p>Unlike Diagnostic data frames which have a defined layout that is well documented and consistent, raw data frames have only the basic CAN frame layout, as shown above, channels one though to eight can represent anything and data can use multiple or single channels with a range of 0 to 255 to represent their values, often the layout is manufacturer or vehicle specific.</p><p>The ID frame represents a specific set of data and will always represent the same values assigned to it. For instance, the frame with ID 520 on the diagnostics port of a Peugeot 407 always represents the following data:<br> &lt; 520, RPM, Voltage, Turbo pressure, Brake Light, 0, 0, 0, 0 &gt;</p><p>ID 520 will always represent those four pieces of information on the diagnostic port, but the data itself may change values. Although eight bytes are used to represent the data of the frame, only the first four channels of the frame are actually In use potentially wasting 4 bytes of bandwidth. The reasoning behind this is manufacturer specific; it is unknown why they chose to represent these four values only and leave other channels empty.</p><h4 id="_4-2-binary-and-bitwise-operations" tabindex="-1">4.2 Binary and Bitwise Operations <a class="header-anchor" href="#_4-2-binary-and-bitwise-operations" aria-label="Permalink to &quot;4.2 Binary and Bitwise Operations&quot;">​</a></h4><p>In order to interpret the data in each channel of the CAN frames, the information would need to be interpreted using bitwise operations.</p><p>The vehicle encodes the status of systems using a form of binary encoding. Each channel can be a value of 0 to 255 with 0 being nothing activated and 255 being everything activated. If you deconstruct the value into binary, you get 00000000 for 0 and 11111111 for 255. Each digit which can only be 1 or 0 represents a different state for a system, if we assume the number representing 32 is the left indicator and the number representing 64 is the right indicator, we know if the value of the channel is 96 that both indicators must be activated, or if the value is 32 only the left indicator is activated.</p><h3 id="step-9-part-5-reverse-engineering-can-information" tabindex="-1">Step 9: Part 5: Reverse Engineering CAN Information. <a class="header-anchor" href="#step-9-part-5-reverse-engineering-can-information" aria-label="Permalink to &quot;Step 9: Part 5: Reverse Engineering CAN Information.&quot;">​</a></h3><h4 id="reverse-engineering-can-information" tabindex="-1">Reverse engineering CAN information. <a class="header-anchor" href="#reverse-engineering-can-information" aria-label="Permalink to &quot;Reverse engineering CAN information.&quot;">​</a></h4><p>Now that you understand how a CAN bus frame works, you need to be able to link a data frame to the data it represents.</p><h4 id="_5-1-analysis-method-serial-monitor" tabindex="-1">5.1 Analysis method: Serial Monitor <a class="header-anchor" href="#_5-1-analysis-method-serial-monitor" aria-label="Permalink to &quot;5.1 Analysis method: Serial Monitor&quot;">​</a></h4><p>For retrieving the raw data from CAN , there are a number of methods and tools to assist in the process. The initial method for interpreting what each frame on the network represents is to do the following steps:</p><ol><li>log a few seconds of all raw data coming through the network and save this in a document.</li><li>One by one pick a frame from the list and change the code to filter all but that frame.</li><li>Trigger events in the vehicle and note changes.</li><li>Remove that frame from the list</li><li>Repeat from step 2.</li></ol><p>This is a long process but will allow you to easily correlate the data on a CAN network to the frame you are monitoring. In order to set a filter in the Arduino code to only show one frame though serial monitor, change the value -1 to the ID you are working on and != to ==, for the line “if(message.id != -1) {“ in the code.</p><p>e.g: “if(message.id != -1) {“ to “if(message.id == 520) {“</p><h4 id="_5-2-alternative-analysis-method-serial-plot" tabindex="-1">5.2 Alternative analysis method: Serial Plot <a class="header-anchor" href="#_5-2-alternative-analysis-method-serial-plot" aria-label="Permalink to &quot;5.2 Alternative analysis method: Serial Plot&quot;">​</a></h4><p>SerialPlot was the next tool for use in reverse engineering and interpreting the data.</p><p>It can produce a live graph of each channel on the same graph or on separate smaller graphs.The tool allowed data to be exported or viewed live. SerialPlot allows trends and behaviours to be viewed easily and relative changes in data can be spotted and interpreted. one of the included images is a sample of frame 1294 forms the Peugeot 407; the sample explains what each channel of that frame does for channels that have changing data.</p><h4 id="_5-3-alternative-analysis-method-supersniffer" tabindex="-1">5.3 Alternative Analysis Method: SuperSniffer <a class="header-anchor" href="#_5-3-alternative-analysis-method-supersniffer" aria-label="Permalink to &quot;5.3 Alternative Analysis Method: SuperSniffer&quot;">​</a></h4><p>Whilst working on the raw information , Serial Monitor and SerialPlot can be a bottleneck for locating useful CAN frames as each frame has to be picked one by one from the listing due to it not being supported. This is where another tool became very useful.</p><p>Once you have the process of retrieving data and processing it using the aforementioned processes, you may wish to try using SuperSniffer. The supplied code for reading messages on the CAN bus network is already configured to work with SuperSniffer.</p><p>SuperSniffer is a software tool built specifically for analysis of CAN bus.</p><p>It requires data to be fed into it in a specific format which was an easy task to complete as the data was already being outputted from the Arduino in a CSV format, the only change necessary was the addition of chevron brackets at the start and finish of the frame. SuperSniffer operates in a similar manner to Wireshark; it displays a live feed of data with a number of coulombs which give statistics about the data, the important coulombs being the CAN frame, message count, change count and ASCII.</p><p>The CAN frame contains the relevant CAN data, the message counter, counts how many times the same frame has been refreshed, the change count counts how many times the same frame has been changed, and the ASCII Coulombe converts the frame to ASCII which allows one to detect if the frame contains text visually.</p><p>The software also features the ability to auto-hide frames that do not change for a specified amount of time and reveal them back into view should they change.</p><p>To install SuperSniffer refer to the software sources section of the document.</p><h4 id="_5-4-methods-for-removable-hardware" tabindex="-1">5.4 Methods for removable hardware <a class="header-anchor" href="#_5-4-methods-for-removable-hardware" aria-label="Permalink to &quot;5.4 Methods for removable hardware&quot;">​</a></h4><p>If the network you are intercepting data from is connected to a removable module, the approach to interpreting the data can be drastically different as recorded data can be played into the hardware or custom commands could be injected without risk of damaging the vehicle. The demo code entitled “Demo 3” will allow you to send custom messages using joystick of the Sparkfun shield to the change the values live.</p><h4 id="_5-4-1-record-and-playback" tabindex="-1">5.4.1 Record And Playback <a class="header-anchor" href="#_5-4-1-record-and-playback" aria-label="Permalink to &quot;5.4.1 Record And Playback&quot;">​</a></h4><p>Instead of targeting frames one by one, activating systems in the vehicle and observing each frame, a new approach can be taken whereby the communications between the vehicle and module are recorded whilst every conceivable system relevant to the module is activated, then, because the module in the vehicle is removable, the data can be played back into the module whilst it is powered on a desk rather than in the vehicle and the behaviors observed.</p><h4 id="_5-4-2-brute-force-injection" tabindex="-1">5.4.2 Brute force injection <a class="header-anchor" href="#_5-4-2-brute-force-injection" aria-label="Permalink to &quot;5.4.2 Brute force injection&quot;">​</a></h4><p>Coupled with the record and playback methods, brute force data injection can also be used. The method of feeding in frames one by one starting at ID 0 and fluctuating each channel from 0 to 255 allows for the documenting of behaviours the module supports but the vehicle may not and behaviours that may not have been possible to activate manually such as engine or airbag faults.</p><h4 id="_5-4-3-safety" tabindex="-1">5.4.3 Safety <a class="header-anchor" href="#_5-4-3-safety" aria-label="Permalink to &quot;5.4.3 Safety&quot;">​</a></h4><p>The aforementioned new approaches are not safe on the diagnostics port or on any network in the vehicle as they could cause damage to safety-critical devices, activated dangerous behaviours such as airbags or engine start or damage difficult/expensive to replace components. Whereas with a module being removable, It may be cheap to obtain, easy to access and replace and will not cause immediate danger if damaged or operated out of designed parameters.</p><h4 id="_5-5-testing-your-interpreted-data" tabindex="-1">5.5 testing your interpreted data. <a class="header-anchor" href="#_5-5-testing-your-interpreted-data" aria-label="Permalink to &quot;5.5 testing your interpreted data.&quot;">​</a></h4><p>Now that you have produced some data from interpreting CAN bus frames, it is time to test if your interpretations are correct by producing code with conditional statements that detect if the expected values occur.</p><p>When producing a conditional statement for detecting the state of indicators, we need a way to determine if the channel contains the value 32. A number of solutions are possible such as converting the decimal value into binary and parsing the string of 1s and 0s. However, a simple solution is to use an operator built into C++ called ‘bitwise AND’, which is represented by the ampersand symbol &amp;.</p><p>Take the bitwise operator and place it between a decimal value and the test value, if the result of the operation is the test value, then you know the decimal value contains the test value. An example of this is: if((input &amp; 64) == 64){ //right indicator activated } (Arduino.cc, 2018).</p><p>The demonstration code entitled “Demo 4” provides the code you need to test your interpretations. It is currently configured to check channel 4 for the value 128 of the frame with ID 54.</p><h4 id="_5-6-interpreting-cluster-communications-in-a-peugeot-407" tabindex="-1">5.6 Interpreting Cluster Communications in a Peugeot 407 <a class="header-anchor" href="#_5-6-interpreting-cluster-communications-in-a-peugeot-407" aria-label="Permalink to &quot;5.6 Interpreting Cluster Communications in a Peugeot 407&quot;">​</a></h4><p>Whilst testing the cluster in the vehicle and during playback of recorded data, it was a simple process to identify which frames represented RPM, Speed and several other indicators, however, some frames proved to be a much bigger challenge to locate to obtain the desired information. These included the oil temperature, fuel level, coolant temperature and several images displayed on the clusters display. This is because the data changes are slow or change rarely.</p><p>During the process of data injection to try find the missing frames, it was observed that even when frames known to move the dials were fed in, nothing happened.</p><p>The reason behind this was difficult to find and also happened to be the solution to the previously mentioned problem of slow or rarely changing data.</p><p>In order to find the reason behind the behaviour, the recorded data had frames removed one by one whilst being played into the cluster; the intention was only to have the frames specific to moving the RPM and speed dials.</p><p>During the process, it was discovered that In order to move the dials you need to feed an enable frame with ID 246 and specific channel values into the cluster every few seconds or the dials will lock back in position zero. You can then send the frames for speed, RPM and fuel level to have the dials move.</p><p>Incidentally, it was observed that the frame that enabled the dials also happens to contain the channel for oil temperature, engines status, the mileage counter and the indicator lights thus solving the missing values problem.</p><h3 id="step-10-part-6-building-an-interface" tabindex="-1">Step 10: Part 6: Building an Interface <a class="header-anchor" href="#step-10-part-6-building-an-interface" aria-label="Permalink to &quot;Step 10: Part 6: Building an Interface&quot;">​</a></h3><h4 id="building-an-interface" tabindex="-1">Building an Interface <a class="header-anchor" href="#building-an-interface" aria-label="Permalink to &quot;Building an Interface&quot;">​</a></h4><p>Now that the reverse engineering part of the project is understood and documentation on the vehicle&#39;s network is produced, it is time to build an interface to use this data.</p><h4 id="_6-1-software-interface" tabindex="-1">6.1 Software interface <a class="header-anchor" href="#_6-1-software-interface" aria-label="Permalink to &quot;6.1 Software interface&quot;">​</a></h4><p>The images with a slider shows a simple Java program. This program works in conjunction with an Arduino to display a slider on the screen which is controlled by a dial connected to the Arduino. Building a graphical interface, depending on the method chosen, is likely to be one of the most difficult but rewarding methods for displaying the interpreted information. Almost complete freedom is afforded in the design, and the result is easy to duplicate.</p><p>The problem with this type of interface is its limitations, should you wish to build an interface to be fixed in a vehicle, you would need a computer such as a Raspberry Pi to drive the display and run the software interface, this means the user would have to wait for boot up and security risks may need to be factored in if the device is running critical safety systems.</p><p>To try the Java example program, refer to the demo code entitled “Demo 5”</p><h4 id="_6-2-hardware-interface" tabindex="-1">6.2 Hardware Interface <a class="header-anchor" href="#_6-2-hardware-interface" aria-label="Permalink to &quot;6.2 Hardware Interface&quot;">​</a></h4><p>There are several avenues for building an interface to display information retrieved from the CAN network; some are simple and easy to implement such as using LEDs or 7 segment displays, others are far more complex using embedded computers, as mentioned in the previous section. The solution used as an example in this tutorial is a compromise between the simple and complex options discussed.</p><p>An Arduino which is connected to the CAN bus will retrieve data from the network.</p><p>The data will be processed using logical operations as discussed in section 5.5; the program will interpret the frames and the data they contain; the relevant information will then be sent to displays connected to the Arduino.</p><h4 id="_6-3-display-hardware" tabindex="-1">6.3 Display Hardware <a class="header-anchor" href="#_6-3-display-hardware" aria-label="Permalink to &quot;6.3 Display Hardware&quot;">​</a></h4><p>Most displays that exist for the Arduino UNO are expensive in large display sizes, processor intensive; requiring the Arduino to draw the display or pin hogs; using up most IO on the Arduino.</p><p>The Nextion display is a “Smart” display; it contains its own processor, Inputs and Outputs, memory and SD card interface, It can run independently or in conjunction with other hardware using serial communication.</p><p>It supports a very basic programming language and a very capable graphical programming interface called Nextion editor that runs on a PC. You can design your GUI in the Nextion editor with simple drag and drop operations and control the icons and gauges with commands using its custom programming language.</p><p>For projects that heavily utilise an Arduino, a display such as the Nextion is an excellent option; it provides a lot of flexibility in designing your interface without the difficulty of programming it. Although expensive when compared with other “dumb” displays such as the one shown in the images above , they offer several features aside from ease of use such as being compact at four times thinner than the Arduino shield display and independent not requiring the Arduino to use its very limited resources to drive the display in addition to whatever else it may be doing.</p><p>For very simple projects that utilise an Arduino, the generic LCD display may be better suited due to its low price. However, time constraints need to be factored in as programming the interface for these displays can be difficult and slow going.</p><p><strong>The Nextion 2.4” display:</strong></p><ul><li>Cost - £12</li><li>Dimensions – 60 x 40 x 6mm</li><li>Operation – Completely Independently or in conjunction with other hardware</li><li>Features – General Purpose Input Outputs, Real Time Clock, RGB Screen, Touchscreen.</li><li>Control – Can control other hardware or be controlled by other hardware</li></ul><p><strong>Generic Arduino 2.4” display:</strong></p><ul><li>Cost - £3 + Arduino</li><li>Dimensions – 60 x 40 x 24mm</li><li>Operation – Requires Arduino to operate</li><li>Features – RGB Screen, Touchscreen.</li><li>Control – Can be controlled by Arduino.</li></ul><h4 id="_6-4-interface-using-nextion" tabindex="-1">6.4 Interface using nextion <a class="header-anchor" href="#_6-4-interface-using-nextion" aria-label="Permalink to &quot;6.4 Interface using nextion&quot;">​</a></h4><p>The displays have their programming transferred via micro SD card, as such when designing an enclosure for the displays, ensure the placement of the screens in the design allows for easy access to the SD card slot to program them.</p><p>Whilst designing an interface, you may go through several iterations of an idea to produce a clean result. one of the images show testing of a needle gauge design, The limitations of the display meant that images could not be rotated to simulate the needle of a gauge moving. However, the displays are capable of operating similar to a video by showing lots of images successively to simulate smooth motion. The problem is, manually moving the needle and capturing its image for each position would take hours of work, however, there is a much simpler solution, the needle design and background image can be imported into video editing software where the needle image is rotated to produce a video of the needle moving from minimum to maximum position, the video can then exported as hundreds of frames.</p><p>Alexander Richardson, a freelance graphic designer, volunteered to assist after seeing the prototype interface, in creating the GUI based on the design requirements and limitations identified.<br> Several design iterations gave the result shown in the images for this step.</p><p>For help on using Nextion displays, please refer to the electronics and programming resources.</p><h3 id="step-11-​equipment-sources" tabindex="-1">Step 11: ​Equipment Sources <a class="header-anchor" href="#step-11-​equipment-sources" aria-label="Permalink to &quot;Step 11: ​Equipment Sources&quot;">​</a></h3><h4 id="equipment-sources" tabindex="-1">Equipment Sources <a class="header-anchor" href="#equipment-sources" aria-label="Permalink to &quot;Equipment Sources&quot;">​</a></h4><p><strong>Multimeter:</strong></p><p><a href="https://amzn.to/2Ec2VOj" target="_blank" rel="noreferrer">https://amzn.to/2Ec2VOj</a></p><p>Soldering iron kit:</p><p><a href="https://amzn.to/2JdF0Si" target="_blank" rel="noreferrer">https://amzn.to/2JdF0Si</a></p><p><a href="https://amzn.to/2uKoPsC" target="_blank" rel="noreferrer">https://amzn.to/2uKoPsC</a></p><p><a href="https://amzn.to/2q2ePoC" target="_blank" rel="noreferrer">https://amzn.to/2q2ePoC</a></p><p><strong>Sparkfun CAN bus shield:</strong></p><p><a href="https://amzn.to/2pXhjVq" target="_blank" rel="noreferrer">https://amzn.to/2pXhjVq</a></p><p><a href="https://amzn.to/2H56EjF" target="_blank" rel="noreferrer">https://amzn.to/2H56EjF</a></p><p><a href="https://goo.gl/oSMiqL" target="_blank" rel="noreferrer">https://goo.gl/oSMiqL</a></p><p><strong>DB9 to OBD2 cable:</strong></p><p><a href="https://amzn.to/2pYqswZ" target="_blank" rel="noreferrer">https://amzn.to/2pYqswZ</a></p><p><a href="https://amzn.to/2Edz5sw" target="_blank" rel="noreferrer">https://amzn.to/2Edz5sw</a></p><p><strong>Arduino UNO:</strong></p><p><a href="https://amzn.to/2Gq9x1q" target="_blank" rel="noreferrer">https://amzn.to/2Gq9x1q</a></p><p><a href="https://amzn.to/2pZTigz" target="_blank" rel="noreferrer">https://amzn.to/2pZTigz</a></p><p><strong>Arduino wiring set:</strong></p><p><a href="https://amzn.to/2uEwatr" target="_blank" rel="noreferrer">https://amzn.to/2uEwatr</a></p><p><a href="https://amzn.to/2EdrKcB" target="_blank" rel="noreferrer">https://amzn.to/2EdrKcB</a></p><p><strong>Arduino Pin headers:</strong></p><p><a href="https://amzn.to/2pZIqPA" target="_blank" rel="noreferrer">https://amzn.to/2pZIqPA</a></p><p><a href="https://amzn.to/2pZIOh0" target="_blank" rel="noreferrer">https://amzn.to/2pZIOh0</a></p><p><a href="https://amzn.to/2pZJ2om" target="_blank" rel="noreferrer">https://amzn.to/2pZJ2om</a></p><p><strong>Nextion displays:</strong></p><p>7”</p><p><a href="https://amzn.to/2GJCx3D" target="_blank" rel="noreferrer">https://amzn.to/2GJCx3D</a></p><p>5”</p><p><a href="https://amzn.to/2uEePAO" target="_blank" rel="noreferrer">https://amzn.to/2uEePAO</a></p><p>4.3”</p><p><a href="https://amzn.to/2GvAIUq" target="_blank" rel="noreferrer">https://amzn.to/2GvAIUq</a></p><p><a href="https://amzn.to/2pXWLfs" target="_blank" rel="noreferrer">https://amzn.to/2pXWLfs</a></p><p>3.2”</p><p><a href="https://amzn.to/2GvnqHC" target="_blank" rel="noreferrer">https://amzn.to/2GvnqHC</a></p><p>2.8”</p><p><a href="https://amzn.to/2GrN6op" target="_blank" rel="noreferrer">https://amzn.to/2GrN6op</a></p><p>2.4”</p><p><a href="https://amzn.to/2pZC5DY" target="_blank" rel="noreferrer">https://amzn.to/2pZC5DY</a></p><p><a href="https://amzn.to/2GIFOQL" target="_blank" rel="noreferrer">https://amzn.to/2GIFOQL</a></p><p><strong>Oscilloscope:</strong></p><p><a href="https://amzn.to/2IjIDVC" target="_blank" rel="noreferrer">https://amzn.to/2IjIDVC</a></p><p>Below are links to various suppliers on Amazon for the electronics used in this tutorial, these are UK affiliate links to Amazon and as such if outside the UK, when you have selected one of these links, change the .co.uk to .com or your countries respective URL.</p><h4 id="software-sources" tabindex="-1">Software Sources <a class="header-anchor" href="#software-sources" aria-label="Permalink to &quot;Software Sources&quot;">​</a></h4><p>In order to program the Arduino you will need to download the Arduino IDE, It is available from <a href="https://www.arduino.cc/en/Main/Software" target="_blank" rel="noreferrer">https://www.arduino.cc/en/Main/Software</a></p><p>In order to process CAN bus data efficiently, it is recommended you download SerialPlot from <a href="https://bitbucket.org/hyOzd/serialplot" target="_blank" rel="noreferrer">https://bitbucket.org/hyOzd/serialplot</a></p><p>and SuperSniffer from <a href="http://techtinker.co.za/forum/viewtopic.php?f=14&amp;t=18" target="_blank" rel="noreferrer">http://techtinker.co.za/forum/viewtopic.php?f=14&amp;...</a></p><h4 id="electronics-and-programming-resources" tabindex="-1">Electronics and Programming resources <a class="header-anchor" href="#electronics-and-programming-resources" aria-label="Permalink to &quot;Electronics and Programming resources&quot;">​</a></h4><p>This section contains links to resources that can educate you on the physics and concepts behind electronic circuitry.</p><p>It is recommended you purchase a kit to learn the basics such as the one linked here: <a href="https://amzn.to/2GvGSUy" target="_blank" rel="noreferrer">https://amzn.to/2GvGSUy</a></p><p><a href="https://www.electronics-tutorials.ws" target="_blank" rel="noreferrer">https://www.electronics-tutorials.ws/ </a>is the recommended source for learning the electronics and some programming knowledge required to follow this document.</p><p>Please learn the following topics:</p><ul><li>Binary numbers</li><li>DC circuits</li><li>Input/output devices</li></ul><p>And for further knowledge to assist with following this document, please learn:</p><ul><li>logic gates</li><li>Systems</li></ul><p>For Programming knowledge, please refer to: <a href="https://www.arduino.cc/en/Guide/ArduinoUno" target="_blank" rel="noreferrer">https://www.arduino.cc/en/Guide/ArduinoUno</a></p><p>Followed by: <a href="https://www.arduino.cc/en/Tutorial/BuiltInExamples" target="_blank" rel="noreferrer">https://www.arduino.cc/en/Tutorial/BuiltInExample...</a></p><p>Please work through the following to understand how the Arduino operates:</p><ul><li>Section 1: Analog Read Serial</li><li>Section 1: Digital Read Serial</li><li>Section 2: Button</li><li>Section 2: Debounce</li><li>Section 4: Serial Passthrough</li><li>Section 5: Arrays</li><li>Section 5: For loop</li><li>Section 5: If statements</li><li>Section 5: While statements</li></ul><p>For knowledge relating to networks, please refer to the following resource:</p><p><a href="https://en.wikipedia.org/wiki/Network_topology" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Network_topology</a></p><p>Please read about:</p><ul><li>Bus networks</li><li>Star networks</li><li>Point to Point networks</li></ul><p>For knowledge related to locating CAN bus lines, please refer to:</p><p><a href="https://www.testandmeasurementtips.com/exploring-canbus-oscilloscope/" target="_blank" rel="noreferrer">https://www.testandmeasurementtips.com/exploring-c...</a></p><p>For knowledge on how CAN bus works electrically, please refer to: <a href="https://en.wikipedia.org/wiki/CAN_bus" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/CAN_bus</a></p><p>Go to the Architecture section.</p><p>For knowledge on how to solder, please refer to:</p><p>For knowledge on how to setup and use the Sparkfun shield, please refer to:</p><p><a href="https://learn.sparkfun.com/tutorials/can-bus-shield-hookup-guide" target="_blank" rel="noreferrer">https://learn.sparkfun.com/tutorials/can-bus-shiel...</a></p><p>To download the Sparkfun Arduino library code, please refer to:</p><p><a href="https://github.com/sparkfun/SparkFunCAN-Bus_Arduino_Library/archive/master.zip" target="_blank" rel="noreferrer">https://github.com/sparkfun/SparkFunCAN-Bus_Arduin...</a></p><p>For knowledge on how to determine the baud rate of CAN bus using an oscilloscope, please refer to: <a href="https://racelogic.support/02VBOX_Motorsport/01General_Information/Knowledge_Base/How_to_measure_CAN_bus_Baud_rate_using_an_oscilloscope" target="_blank" rel="noreferrer">https://racelogic.support/02VBOX_Motorsport/01Gen...</a></p><p>For knowledge on how to operate a Nextion display refer to:</p><p><a href="https://www.itead.cc/wiki/Nextion_Editor_Quick_Start_Guide" target="_blank" rel="noreferrer">https://www.itead.cc/wiki/Nextion_Editor_Quick_Sta...</a></p><p>For knowledge on how to operate the inexpensive Arduino display, please refer to:</p><p><a href="https://www.adafruit.com/product/2478" target="_blank" rel="noreferrer">https://www.adafruit.com/product/2478</a></p><h3 id="step-12-demonstration-code" tabindex="-1">Step 12: Demonstration Code <a class="header-anchor" href="#step-12-demonstration-code" aria-label="Permalink to &quot;Step 12: Demonstration Code&quot;">​</a></h3><h4 id="demo1-can-bus-data-retrieval" tabindex="-1">Demo1 - CAN bus data retrieval <a class="header-anchor" href="#demo1-can-bus-data-retrieval" aria-label="Permalink to &quot;Demo1 - CAN bus data retrieval&quot;">​</a></h4><p>The demo1 code, coupled with the Arduino library which you can download using the link in the electronics and programming resources page, Is all you need to receive data from a CAN bus network and display it via the Arduino IDE’s built-in serial monitor.</p><h4 id="demo-2-can-bus-send-and-receive-messages" tabindex="-1">Demo 2 - CAN bus send and receive messages <a class="header-anchor" href="#demo-2-can-bus-send-and-receive-messages" aria-label="Permalink to &quot;Demo 2 - CAN bus send and receive messages&quot;">​</a></h4><p>The demo2 code allows you to send and receive CAN bus messages. It is only slightly different from the previous code because it has additional lines, but the previous lines to read messages remain.</p><h4 id="demo-3-can-bus-send-custom-messages-using-joystick" tabindex="-1">Demo 3 - CAN bus send custom messages using joystick <a class="header-anchor" href="#demo-3-can-bus-send-custom-messages-using-joystick" aria-label="Permalink to &quot;Demo 3 - CAN bus send custom messages using joystick&quot;">​</a></h4><p>In order to streamline the process of sending custom messages to devices so that you can change the values with the program running rather than by reuploading new values, this code will allow you to control the value of each channel with the joystick.</p><h4 id="demo-4-can-frame-data-check" tabindex="-1">Demo 4 - CAN frame data check. <a class="header-anchor" href="#demo-4-can-frame-data-check" aria-label="Permalink to &quot;Demo 4 - CAN frame data check.&quot;">​</a></h4><p>This code is a variation on the demo code used to read values from a network; it has been modified to only check if channel 4 of frame 54 contains the value 128.</p><p>You should change the values in the function called dataInterpreter to represent frames you have identified and interpreted. Should you wish to compare different channels or different frame ID’s at the same time without changing the values in code, you will need to add additional functions to the code.</p><p>Each id function is called in dataInterpreter, if it matches the expected ID, the corresponding function for that it is called, the function checks if the channel sent to it is the one expected and then checks if the content of that channel contains the desired value.</p><h4 id="demo-5-java-graphical-interface-demo-program" tabindex="-1">Demo 5 - Java graphical interface demo program <a class="header-anchor" href="#demo-5-java-graphical-interface-demo-program" aria-label="Permalink to &quot;Demo 5 - Java graphical interface demo program&quot;">​</a></h4><p>The file entitled slider.java is a Java program, to use it, you will need to follow the Java tutorial here: <a href="https://docs.oracle.com/javase/tutorial/getStarted/cupojava/win32.html" target="_blank" rel="noreferrer">https://docs.oracle.com/javase/tutorial/getStarted/cupojava/win32.html</a></p><p>This tutorial will explain how to download and install Java, create a simple Java program and run it. Where the tutorial gives you example code, simply replace the example code with this code.</p><p>You will then need to program an Arduino to output a number though serial print statements; the Arduino serial needs to be running at a baud of 38400, when you run the Java program and connect it to the Arduino, the slider will move to represent the value, the Arduino is outputting.</p><h3 id="step-13-the-final-result" tabindex="-1">Step 13: The Final Result <a class="header-anchor" href="#step-13-the-final-result" aria-label="Permalink to &quot;Step 13: The Final Result&quot;">​</a></h3><h3 id="step-14-references" tabindex="-1">Step 14: References <a class="header-anchor" href="#step-14-references" aria-label="Permalink to &quot;Step 14: References&quot;">​</a></h3><p>Avionics. (2018). CAN Bus in Aviation - Avionics. [online] Available at: <a href="http://www.aviationtoday.com/2009/05/01/can-bus-in-aviation/" target="_blank" rel="noreferrer">http://www.aviationtoday.com/2009/05/01/can-bus-in-aviation/</a> [Accessed 21 Mar. 2018].</p><p>Walz, E. (2018). Automotive Networking: CAN-bus Topology. [online] linked in. Available at: <a href="https://www.linkedin.com/pulse/automotive-networking-can-bus-topology-eric-walz/" target="_blank" rel="noreferrer">https://www.linkedin.com/pulse/automotive-networking-can-bus-topology-eric-walz/</a> [Accessed 12 Mar. 2018].</p><p>OBD Solutions. (2017). What is OBD? - OBD Solutions. [online] Available at: <a href="http://www.obdsol.com/knowledgebase/on-board-diagnostics/what-is-obd/" target="_blank" rel="noreferrer">http://www.obdsol.com/knowledgebase/on-board-diagnostics/what-is-obd/</a> [Accessed 29 Nov. 2017].</p><p>Arduino.cc. (2018). Arduino Reference. [online] Available at: <a href="https://www.arduino.cc/reference/en/language/structure/bitwise-operators/bitwiseand/" target="_blank" rel="noreferrer">https://www.arduino.cc/reference/en/language/structure/bitwise-operators/bitwiseand/</a> [Accessed 15 Mar. 2018].</p><p>Vector.com. (2018). Vector Solution for CAN. [online] Available at: <a href="https://vector.com/vi%5C_can%5C_solutions%5C_en.html" target="_blank" rel="noreferrer">https://vector.com/vi\\_can\\_solutions\\_en.html</a> [Accessed 21 Nov. 2017].</p><h3 id="be-the-first-to-share" tabindex="-1">Be the First to Share <a class="header-anchor" href="#be-the-first-to-share" aria-label="Permalink to &quot;Be the First to Share&quot;">​</a></h3><h3 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h3>',302)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
